---region currency
function LSdkCpHaoChen:_GetCurrencyParams()
    --港币 HKD，符号：HK$
    --台币TWD ，符号：NT$
    --澳门MOP， 符号：MOP$
    --美元USD， 符号：$
    if LGameSettings.platformRegion == LRegionConst.KOREA then
        return "₩", "KRW"
    end
    return "$", "USD"
end

function LSdkCpHaoChen:_InitCurrency()
    local symbol, currency = self:_GetCurrencyParams()
    self._currencySymbol = symbol
    self._currency = currency
end

function LSdkCpHaoChen:DoPayOrderRequest(payData, tgaData)
    local payPointRef = gModelPay:GetWelfareProductPayPointRef(payData.payPointRefId)
    local produceCp = ""
    local payCurrency = ""
    if payPointRef then
        local money
        produceCp, money, payCurrency = self:GetProductParam(payPointRef)
        local price = tonumber(money) or 0
        self._impl:CallTrack("OnPayOrderRequest", payData.goodsId, produceCp,price)
    end


    LSdkCpBase.DoPayOrderRequest(self, payData, tgaData)

end

function LSdkCpHaoChen:GetCurrency()
    if string.isempty(self._currency) then
        self:_InitCurrency()
    end
    return self._currency
end

function LSdkCpHaoChen:GetCurrencySymbol()
    if string.isempty(self._currencySymbol) then
        self:_InitCurrency()
    end
    return self._currencySymbol
end

