--on cp message

function LSdkCpHaoChen:OnLoginResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        self._sAccId = args[2]
        self._sToken = args[3]
        self._sAccount = args[4]
        self._isBindEmail = args[5] == "0"

        self:_InternalStartWebValidUser()
    else
        self._sUserId = ""
        self._sToken = ""

        self._lastLoginError = args[2] or ""

        self:LoginFailure()
    end
end

function LSdkCpHaoChen:_InternalStopWebValidUser()
    if self._webReq then
        self._webReq:Destroy()
        self._webReq = nil
    end
end

function LSdkCpHaoChen:_InternalStartWebValidUser()
    if string.isempty(self._sToken) then return end
    self._isValidUser = false
    local webReq = self._webReq
    if webReq and not webReq:IsDestroy() then
        if webReq:IsSameValidReqParam(self._sToken) then -- 同样的验证码
            if not webReq:IsFinished() or webReq:IsOK() then
                --正在请求或者，已经请求成功了获得了结果，不再请求
                return
            end
        end
    end

    self:_InternalStopWebValidUser()

    webReq = LCpWebReq:New()
    self._webReq = webReq

    webReq:SetValidReqParam(self._sToken)

    local sToken = self._sToken or ""
    local sign = string.upper(CS.md5FromString(sToken..LGameLogin.AuthKey))
    local tokenTbl = {
        "token="..sToken,
        "sign="..sign
    }
    local paramPart = table.concat(tokenTbl, "&")
    local params = "zdmz/loginVerify.do?"..paramPart

    local urlList = gLGameLogin:GetServicesUrlList()
    --print("gt ServicesUrl: " .. url)

    webReq:StartReq(urlList, params, function (ret, result)
        if ret ~= CS.YXWebRet.ok then
            GF.ShowMessage(ccClientText(140))
            LogError("AuthCodeError ...")
            self:_InternalStopWebValidUser() --销毁可以进行下次验证
            self._lastLoginError = "AuthCodeError"
            self:LoginFailure()
        else
            local code = tostring(result.code)
            if(code == "0") then
                 local data = result.result
                 local accId = tostring(data["accid"])
                 self._sRegisterTime = data["reg_ts"]
                 self._serverTimestamp = data["timestamp"]
                 local oldUid = tostring(data["jodo_uid"])
                if oldUid ~= "0" and oldUid ~= "nil" and not string.isempty(oldUid) then
                    self._sUserId = oldUid
                else
                    self._sUserId = accId
                end
                self._isValidUser = true
                self:LoginOk()
                print("gt sdk loginOk")
            else
                GF.ShowMessage(ccClientText(140))
                LogError("error AuthCode response code = "..tostring(code).."|"..tostring(result.data))
                self:_InternalStopWebValidUser() --销毁可以进行下次验证
                self._lastLoginError = "AuthCode response code = "..tostring(code)
                self:LoginFailure()
            end
        end
    end,true)
end

function LSdkCpHaoChen:OnLogoutResult(args)
    local isOk = toboolean(args[1])
    if isOk then
        local sUserId = args[2]
        if sUserId == self._sAccId then
            self._isValidUser = false
            self._sUserId = ""
            self:LogoutOk()
        end
    end
end

