function LSdkCpHaoChen:OnInitResult(args)
    local isOk = toboolean(args[1])
    if LOG_INFO_ENABLED then
        printInfoN2("zdsdk", "Lua InitResult +++" .. tostring(isOk))
    end
    self._isInit = isOk
    FireEvent(EventNames.SDK_INIT_OK)
    local statusCode = tonumber(args[2])
    local initCount = self._initCount or 0
    initCount = initCount + 1
    self._initCount = initCount
    if gLxPatchCtrl and statusCode and statusCode ~= 0 and not isOk then
        if initCount <= 2 then
            --失败了重初始化两次
            LxTimer.DelayTimeCall(function()
                self:Init()
            end, 0.5)
            return
        end
        gLxPatchCtrl:ShowSysTips(18, tostring(statusCode), function(btnType)
            if btnType == 1 then
                QuitGame()
            elseif btnType == 2 then
                self:Init()
            end
        end, nil)
    end
end

function LSdkCpHaoChen:OnPopupOfficialPaymentSupportedResult(args)
    local isOk = toboolean(args[1])
    local isCanPopup = args[2] == "1"
    self._isCanPopup = isCanPopup
    self._officialPaymentUrl = args[3]
    self._canPopupChecking = true
    FireEvent(EventNames.SDK_SUPPORT_POPUPOFFICIALPAYMENT, self._isCanPopup)
end


return LSdkCpHaoChen
